DROP TABLE IF EXISTS `base_container_factory`;
CREATE TABLE `base_container_factory`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `factory_number` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '堆场编号',
  `factory_id` varchar(32) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '堆场uuid',
  `factory_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '堆场名称',
  `contact_user` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '联系人名称',
  `contact_phone` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '联系人电话',
  `factory_address` varchar(300) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '堆场详细地址',
  `currency_id` int NULL DEFAULT NULL COMMENT '堆存费用币种，base_currency@id',
  `daily_expenses` decimal(12, 4) NULL DEFAULT NULL COMMENT '每日堆存费用',
  `region_id` int NULL DEFAULT NULL COMMENT 'region@id 所属区域节点',
  `credit_code` varchar(60) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '社会信用代码',
  `email` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'email',
  `free_duration` int NULL DEFAULT NULL COMMENT '免费存储时长',
  `boarding_fee` decimal(12, 4) NULL DEFAULT NULL COMMENT '上车费',
  `alighting_fee` decimal(12, 4) NULL DEFAULT NULL COMMENT '下车费',
  `secondary_removal_fee` decimal(12, 4) NULL DEFAULT NULL COMMENT '二次搬移费',
  `proxy_company_id` varchar(32) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '所属代理公司uuid',
  `has_seal` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '1' COMMENT '是否有电子章：0 有 1 没有',
  `use_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '状态：0启用， 1 禁用',
  `create_by` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否逻辑删除，0正常，1删除',
  `version` int NULL DEFAULT NULL COMMENT '版本',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '提箱单备注',
  `create_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `update_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '修改人',
  `factory_type` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '堆场类别：0 境内； 1 境外',
  `proxy_company_name` varchar(32) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '代管公司名称',
  `factory_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '堆场编码',
  `receive_remark` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '还箱指令',
  `remark_return_order` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '还箱单备注',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `p_code`(`contact_user` ASC) USING BTREE,
  INDEX `udx_factory_id`(`factory_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 171 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '地区表--基础配置--堆场维护' ROW_FORMAT = DYNAMIC;

