INSERT INTO `base_container_factory` VALUES (113, 'DC20230530000001', 'b7dbaf90fdf4419491f15611164bce1c', '马拉SJ', 'PIOTR WIKTORUK', '+48 573 180 314', 'SJIUS Depot Dobryń Mały 52A 21-512 Zalesie  GPS: 52.03629525059545, 23.389427544663434', 1, 3.2000, 3665, NULL, 'jialiting@xuhui-logistics.com；PIOTR.WIKTORUK@SJIUS.PL', 0, 38.0000, 38.0000, 0.0000, '8a984ad45f5c44fba015bee845207fe2', '1', '1', '1469889964700938242', '2023-05-30 10:19:15', '1663081331858997250', '2024-10-28 15:40:32', 0, NULL, '1.Please pickup units within the validity period.\n2.Please advise the depot before pickup. If you don\'t make an appointment in advance,please bear all the extra expenses.\n3.Please check the conditions of units at time of pickup. All extra costs resulting from swapping units after pickup will be for customer’s own account.\n4.Working hours: Monday-Friday (Polish Time) (08:00-16:00), except statutory holidays.', '管理员', 'HNXH@xuhui-logistics.com', '1', '海南旭晖国际物流有限公司', 'MS', '2023HNXH-LG', '1.Please contact the depot at least 24 hours prior the pickup/redelivery of units to confirm the containers are available and the depot is ready.\n2.Please clean the containers before dropping off to avoid additional cleaning fees. \n3.The depot loads containers only on trailers that have bolts securing the container (twist-lock). \n4.Working hours: Monday-Friday (Polish Time) (08:00-16:00), except statutory holidays.');
